-- Drop existing policies that cause infinite recursion
DROP POLICY IF EXISTS "Admins can view all profiles" ON public.profiles;
DROP POLICY IF EXISTS "Admins can update all profiles" ON public.profiles;
DROP POLICY IF EXISTS "Admins can manage tasks" ON public.tasks;
DROP POLICY IF EXISTS "Admins can view all completions" ON public.task_completions;
DROP POLICY IF EXISTS "Admins can update completions" ON public.task_completions;
DROP POLICY IF EXISTS "Admins can view all withdrawals" ON public.withdrawals;
DROP POLICY IF EXISTS "Admins can update withdrawals" ON public.withdrawals;
DROP POLICY IF EXISTS "Admins can view all premium requests" ON public.premium_requests;
DROP POLICY IF EXISTS "Admins can update premium requests" ON public.premium_requests;

-- Create a security definer function to check admin status (avoids RLS recursion)
CREATE OR REPLACE FUNCTION public.is_admin(user_id UUID)
RETURNS BOOLEAN AS $$
  SELECT EXISTS (
    SELECT 1 FROM public.profiles
    WHERE id = user_id AND is_admin = TRUE
  );
$$ LANGUAGE sql SECURITY DEFINER STABLE;

-- Re-create admin policies using the security definer function
CREATE POLICY "Admins can view all profiles" ON public.profiles FOR SELECT USING (public.is_admin(auth.uid()));
CREATE POLICY "Admins can update all profiles" ON public.profiles FOR UPDATE USING (public.is_admin(auth.uid()));
CREATE POLICY "Admins can manage tasks" ON public.tasks FOR ALL USING (public.is_admin(auth.uid()));
CREATE POLICY "Admins can view all completions" ON public.task_completions FOR SELECT USING (public.is_admin(auth.uid()));
CREATE POLICY "Admins can update completions" ON public.task_completions FOR UPDATE USING (public.is_admin(auth.uid()));
CREATE POLICY "Admins can view all withdrawals" ON public.withdrawals FOR SELECT USING (public.is_admin(auth.uid()));
CREATE POLICY "Admins can update withdrawals" ON public.withdrawals FOR UPDATE USING (public.is_admin(auth.uid()));
CREATE POLICY "Admins can view all premium requests" ON public.premium_requests FOR SELECT USING (public.is_admin(auth.uid()));
CREATE POLICY "Admins can update premium requests" ON public.premium_requests FOR UPDATE USING (public.is_admin(auth.uid()));

-- Also allow service role to insert profiles (for trigger)
CREATE POLICY "Service role can insert profiles" ON public.profiles FOR INSERT WITH CHECK (TRUE);
